diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..4e6120450f44 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,28 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq/une (select (fcmp ord X, 0.0), X, 0.0), C -> fcmp oeq/une X, C
+      // When C != 0.0, the select returns X when ordered (not NaN), 0.0 otherwise.
+      // For NaN input: select gives 0.0, and (0.0 eq C) = false = (NaN eq C) when C != 0.0
+      // For ordered input: select gives X, and (X eq C) = (X eq C)
+      if ((Pred == FCmpInst::FCMP_OEQ || Pred == FCmpInst::FCMP_UNE) &&
+          !match(RHSC, m_AnyZeroFP())) {
+        SelectInst *SI = cast<SelectInst>(LHSI);
+        Value *TrueVal = SI->getTrueValue();
+        Value *FalseVal = SI->getFalseValue();
+        Value *Cond = SI->getCondition();
+        Value *X;
+        CmpPredicate CmpPred;
+        // Match select condition as (fcmp ord X, 0.0)
+        if (match(Cond, m_FCmp(CmpPred, m_Value(X), m_AnyZeroFP())) &&
+            CmpPred == FCmpInst::FCMP_ORD) {
+          // Verify select arms are X and 0.0
+          if (((TrueVal == X && match(FalseVal, m_AnyZeroFP())) ||
+               (FalseVal == X && match(TrueVal, m_AnyZeroFP())))) {
+            return new FCmpInst(Pred, X, RHSC, "", &I);
+          }
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

